      body: JSON.stringify({ class_title: window.CLASS_TITLE || "Introduction to Photosynthesis", class_slug: CLASS_SLUG, slide: s.id || "", slideNum: String(idx+1), context: _fbContext, text: text })
    }).then(function(r){ return r.json(); }).then(function(j){
      if(j && j.ok){
        trackParticipation("feedback");
        if(muted) muted.textContent = "Thank you — your feedback was recorded.";
